"use strict";(self.webpackChunkmif_docs=self.webpackChunkmif_docs||[]).push([[2256],{5293(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"v0.4.0","label":"v0.4.0","banner":null,"badge":true,"noIndex":false,"className":"docs-version-v0.4.0","isLast":true,"docsSidebars":{"docs":[{"type":"category","label":"Getting Started","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/getting-started/prerequisites","label":"Prerequisites","docId":"getting-started/prerequisites","unlisted":false},{"type":"link","href":"/docs/getting-started/quickstart","label":"Quickstart","docId":"getting-started/quickstart","unlisted":false}]},{"type":"category","label":"Features","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/features/preset","label":"Presets","docId":"features/preset","unlisted":false},{"type":"link","href":"/docs/features/prefill-decode-disaggregation","label":"PD Disaggregation","docId":"features/prefill-decode-disaggregation","unlisted":false},{"type":"link","href":"/docs/features/prefix-cache-aware-routing","label":"Prefix Cache-aware Routing","docId":"features/prefix-cache-aware-routing","unlisted":false}]},{"type":"category","label":"Operations","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/operations/latest-release","label":"Latest Release","docId":"operations/latest-release","unlisted":false},{"type":"category","label":"Monitoring","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/operations/monitoring/metrics/","label":"Metrics","docId":"operations/monitoring/metrics/index","unlisted":false}]},{"type":"link","href":"/docs/operations/hf-model-management-with-pv","label":"HF Model Management (PV)","docId":"operations/hf-model-management-with-pv","unlisted":false},{"type":"link","href":"/docs/operations/multi-model","label":"Multi-model Serving","docId":"operations/multi-model","unlisted":false},{"type":"link","href":"/docs/operations/container-image-caching-with-harbor/","label":"Container image caching (Harbor)","docId":"operations/container-image-caching-with-harbor/index","unlisted":false}]},{"type":"category","label":"Reference","collapsible":true,"collapsed":false,"items":[{"type":"category","label":"Heimdall","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/reference/heimdall/api-reference","label":"API Reference","docId":"reference/heimdall/api-reference","unlisted":false},{"type":"link","href":"/docs/reference/heimdall/plugins","label":"Plugins","docId":"reference/heimdall/plugins","unlisted":false}]},{"type":"category","label":"Odin","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/reference/odin/api-reference","label":"API Reference","docId":"reference/odin/api-reference","unlisted":false}]},{"type":"link","href":"/docs/reference/supported-devices","label":"Supported devices","docId":"reference/supported-devices","unlisted":false}]}]},"docs":{"features/prefill-decode-disaggregation":{"id":"features/prefill-decode-disaggregation","title":"Prefill-Decode Disaggregation","description":"During LLM inference, computation occurs in two stages: prefill and decode. In the prefill phase, the model processes the entire input prompt to generate the first token &mdash; a highly parallel, compute-bound process. The decode phase then predicts one token at a time, reusing the growing KV cache, and is memory-bound.","sidebar":"docs"},"features/prefix-cache-aware-routing":{"id":"features/prefix-cache-aware-routing","title":"Prefix Cache-aware Routing","description":"Prefix caching is a technique that stores the KV cache from previous queries, allowing subsequent queries with an identical prefix to reuse it. This eliminates redundant computation and significantly improves performance for workloads with common prefixes, such as system prompts, conversation history, or shared contextual documents.","sidebar":"docs"},"features/preset":{"id":"features/preset","title":"Presets","description":"The MoAI Inference Framework provides a set of pre-configured InferenceServiceTemplates, known as presets. These presets encapsulate standard configurations for various models and hardware setups, simplifying the deployment of inference services.","sidebar":"docs"},"getting-started/prerequisites":{"id":"getting-started/prerequisites","title":"Prerequisites","description":"This document introduces the prerequisites for the MoAI Inference Framework and provides instructions on how to install them.","sidebar":"docs"},"getting-started/quickstart":{"id":"getting-started/quickstart","title":"Quickstart","description":"This quickstart launches two vLLM instances (pods) of the Llama 3.2 1B Instruct model and serves them through a single endpoint as an example. Please make sure to install all prerequisites, including the following versions of the components, before starting this quickstart guide.","sidebar":"docs"},"operations/container-image-caching-with-harbor/index":{"id":"operations/container-image-caching-with-harbor/index","title":"Container image caching with Harbor","description":"The container images composing the MoAI Inference Framework are distributed through Amazon ECR. Although this approach works well in general, fetching images from a remote registry during deployment and scaling of inference environments may incur substantial delays.","sidebar":"docs"},"operations/hf-model-management-with-pv":{"id":"operations/hf-model-management-with-pv","title":"Hugging Face model management with persistent volume","description":"Efficient management of large language models (LLMs) is crucial for optimizing storage usage and reducing startup times. Instead of downloading models repeatedly for each pod, using a shared Persistent Volume (PV) allows multiple pods to access the same model files.","sidebar":"docs"},"operations/latest-release":{"id":"operations/latest-release","title":"Latest release","description":"The following table lists the latest released versions of MIF components and their bundled dependencies.","sidebar":"docs"},"operations/monitoring/metrics/index":{"id":"operations/monitoring/metrics/index","title":"Metrics Monitoring","description":"This document describes how to access Grafana dashboards to monitor the MoAI Inference Framework and provides an overview of the available metrics. Please make sure to install all prerequisites before starting this monitoring guide.","sidebar":"docs"},"operations/multi-model":{"id":"operations/multi-model","title":"Multi-model serving","description":"Multi-model serving enables serving multiple models through a single endpoint, routing requests to the appropriate model based on the model field in the request body. By combining the Body-Based Router (BBR) with Heimdall schedulers, the MoAI Inference Framework can serve multiple models across different GPU types through a unified API.","sidebar":"docs"},"reference/heimdall/api-reference":{"id":"reference/heimdall/api-reference","title":"Heimdall API Reference","description":"inference.networking.k8s.io/v1","sidebar":"docs"},"reference/heimdall/plugins":{"id":"reference/heimdall/plugins","title":"Heimdall plugins","description":"All plugins are declared in the top-level plugins list of EndpointPickerConfig. Heimdall assigns each plugin to the appropriate extension point based on the interfaces it implements. A single plugin can implement multiple interfaces (e.g., context-length-aware acts as both a Filter and a Scorer).","sidebar":"docs"},"reference/odin/api-reference":{"id":"reference/odin/api-reference","title":"Odin API Reference","description":"odin.moreh.io/v1alpha1","sidebar":"docs"},"reference/supported-devices":{"id":"reference/supported-devices","title":"Supported devices","description":"Accelerator labels","sidebar":"docs"}}}}')}}]);